CREATE TABLE `CoverageCheck` (`id` VARCHAR(191) NOT NULL,`opportunityId` VARCHAR(191) NOT NULL,`siteAddress` TEXT NOT NULL,`circuitCount` INTEGER NOT NULL DEFAULT 1,`status` ENUM('DRAFT','REQUESTED','CONFIRMED','UNAVAILABLE','RETURNED') NOT NULL DEFAULT 'DRAFT',`fiberAvailable` TINYINT(1) NULL,`olt` VARCHAR(191) NULL,`distanceKm` DECIMAL(10,2) NULL,`capacityMbps` INTEGER NULL,`availablePorts` INTEGER NULL,`expectedInstallDate` DATETIME NULL,`confirmedCost` DECIMAL(15,2) NULL,`responderNotes` TEXT NULL,`createdAt` DATETIME NOT NULL,`updatedAt` DATETIME NOT NULL,PRIMARY KEY (`id`),CONSTRAINT `CoverageCheck_opportunityId_fkey` FOREIGN KEY (`opportunityId`) REFERENCES `Opportunity` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `SolutionDesign` (`id` VARCHAR(191) NOT NULL,`opportunityId` VARCHAR(191) NOT NULL,`ntWorkValue` DECIMAL(15,2) NOT NULL,`partnerCost` DECIMAL(15,2) NOT NULL DEFAULT 0,`estimatedCost` DECIMAL(15,2) NOT NULL,`estimatedPrice` DECIMAL(15,2) NOT NULL,`marginPct` DECIMAL(6,2) NOT NULL,`riskNotes` TEXT NULL,`assumptions` TEXT NULL,`createdAt` DATETIME NOT NULL,`updatedAt` DATETIME NOT NULL,PRIMARY KEY (`id`),UNIQUE KEY `SolutionDesign_opportunityId_key` (`opportunityId`),CONSTRAINT `SolutionDesign_opportunityId_fkey` FOREIGN KEY (`opportunityId`) REFERENCES `Opportunity` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `InternalOrder` (`id` VARCHAR(191) NOT NULL,`orderNo` VARCHAR(191) NOT NULL,`quoteId` VARCHAR(191) NOT NULL,`status` ENUM('DRAFT','READY_FOR_HANDOFF','SENT','ACKNOWLEDGED','RETURNED','COMPLETED') NOT NULL DEFAULT 'DRAFT',`omReference` VARCHAR(191) NULL,`crmReference` VARCHAR(191) NULL,`billingReference` VARCHAR(191) NULL,`handoffNotes` TEXT NULL,`sentAt` DATETIME NULL,`acknowledgedAt` DATETIME NULL,`createdAt` DATETIME NOT NULL,`updatedAt` DATETIME NOT NULL,PRIMARY KEY (`id`),UNIQUE KEY `InternalOrder_orderNo_key` (`orderNo`),UNIQUE KEY `InternalOrder_quoteId_key` (`quoteId`),CONSTRAINT `InternalOrder_quoteId_fkey` FOREIGN KEY (`quoteId`) REFERENCES `Quote` (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
